import React, { useState } from "react";
import "./CalendarPage.scss";
import { Course } from "../../Types/course";
import { Deadline as ImportedDeadline } from "../../Types/deadline";
import { Sidebar } from "../../сomponents/Sidebar";

interface Deadline {
  id: string;
  courseId: string;
  taskName: string;
  dueDate: Date;
  status: "upcoming" | "completed";
}

interface CalendarPageProps {
  currentPage: string;
  deadlines: ImportedDeadline[];
  courses: Course[];
  onNavigate: (page: string) => void;
  onLogout: () => void;
  onAddDeadline: (deadline: Omit<Deadline, "id">) => void;
}

// Уникальные имена для TopBar
const TopBar: React.FC<{ userName: string }> = ({ userName }) => {
  return (
    <div className="calendar-topbar">
      <div className="calendar-topbar__content">
        <h1 className="calendar-topbar__title">Academic Calendar</h1>
        <div className="calendar-topbar__user-info">
          <span className="calendar-topbar__welcome-text">Welcome {userName}!</span>
        </div>
      </div>
    </div>
  );
};

// Уникальные имена для модалки
const DeadlineModal: React.FC<{
  courses: Course[];
  onSave: (deadline: Omit<Deadline, "id">) => void;
  onClose: () => void;
}> = ({ courses, onSave, onClose }) => {
  const [taskName, setTaskName] = useState("");
  const [selectedCourseId, setSelectedCourseId] = useState("");
  const [dueDate, setDueDate] = useState("");

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!taskName || !selectedCourseId || !dueDate) return;
    onSave({ courseId: selectedCourseId, taskName, dueDate: new Date(dueDate), status: "upcoming" });
    onClose();
  };

  return (
    <div className="calendar-modal-overlay" onClick={onClose}>
      <div className="calendar-modal" onClick={(e) => e.stopPropagation()}>
        <div className="calendar-modal__header">
          <h3 className="calendar-modal__title">Add New Deadline</h3>
          <button onClick={onClose} className="calendar-modal__close-icon">×</button>
        </div>
        <form onSubmit={handleSubmit} className="calendar-modal__form">
          <div className="calendar-form-field">
            <label className="calendar-form-field__label">Task Name</label>
            <input
              type="text"
              value={taskName}
              onChange={(e) => setTaskName(e.target.value)}
              className="calendar-form-field__input"
              required
            />
          </div>
          <div className="calendar-form-field">
            <label className="calendar-form-field__label">Course</label>
            <select
              value={selectedCourseId}
              onChange={(e) => setSelectedCourseId(e.target.value)}
              className="calendar-form-field__select"
              required
            >
              <option value="">Select a course</option>
              {courses.map((course) => (
                <option key={course.id} value={course.id}>{course.title}</option>
              ))}
            </select>
          </div>
          <div className="calendar-form-field">
            <label className="calendar-form-field__label">Due Date</label>
            <input
              type="date"
              value={dueDate}
              onChange={(e) => setDueDate(e.target.value)}
              className="calendar-form-field__input"
              required
            />
          </div>
          <div className="calendar-modal__footer">
            <button type="button" className="calendar-btn calendar-btn--cancel" onClick={onClose}>Cancel</button>
            <button type="submit" className="calendar-btn calendar-btn--save">Save</button>
          </div>
        </form>
      </div>
    </div>
  );
};

export function CalendarPage({
  currentPage,
  deadlines,
  courses,
  onNavigate,
  onLogout,
  onAddDeadline,
}: CalendarPageProps) {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [showAddModal, setShowAddModal] = useState(false);

  const monthNames = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];

  const getCourseById = (id: string) => courses.find((c) => c.id === id);
  const totalDays = new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 0).getDate();
  const startDay = new Date(currentDate.getFullYear(), currentDate.getMonth(), 1).getDay();

  const days = [];
  for (let i = 0; i < startDay; i++) days.push(null);
  for (let day = 1; day <= totalDays; day++) days.push(day);

  return (
    <div className="calendar-page-layout">
      <Sidebar currentPage={currentPage} onNavigate={onNavigate} onLogout={onLogout} />

      <div className="calendar-main-wrapper">
        <TopBar userName="Student" />

        <main className="calendar-view-port">
          <div className="calendar-content-grid">
            {/* Секция Календаря */}
            <section className="calendar-board">
              <header className="calendar-board__header">
                <h2 className="calendar-board__current-month">
                  {monthNames[currentDate.getMonth()]} {currentDate.getFullYear()}
                </h2>
                <div className="calendar-board__actions">
                  <button className="calendar-btn calendar-btn--nav" onClick={() => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1))}>‹</button>
                  <button className="calendar-btn calendar-btn--today" onClick={() => setCurrentDate(new Date())}>Today</button>
                  <button className="calendar-btn calendar-btn--nav" onClick={() => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1))}>›</button>
                  <button className="calendar-btn calendar-btn--add" onClick={() => setShowAddModal(true)}>+ Add</button>
                </div>
              </header>

              <div className="calendar-grid-system">
                {["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"].map(d => (
                  <div key={d} className="calendar-grid-system__weekday">{d}</div>
                ))}

                {days.map((day, idx) => {
                  if (day === null) return <div key={`empty-${idx}`} className="calendar-grid-system__day calendar-grid-system__day--empty" />;

                  const isToday = new Date().toDateString() === new Date(currentDate.getFullYear(), currentDate.getMonth(), day).toDateString();
                  const dayDeadlines = deadlines.filter(d => {
                    const dd = new Date(d.dueDate);
                    return dd.getDate() === day && dd.getMonth() === currentDate.getMonth() && dd.getFullYear() === currentDate.getFullYear();
                  });

                  return (
                    <div key={day} className={`calendar-grid-system__day ${isToday ? 'calendar-grid-system__day--today' : ''}`}>
                      <span className="calendar-grid-system__date-num">{day}</span>
                      <div className="calendar-grid-system__events-container">
                        {dayDeadlines.slice(0, 2).map(dl => (
                          <div 
                            key={dl.id} 
                            className="calendar-event-tag"
                            style={{ borderLeftColor: getCourseById(dl.courseId)?.color }}
                          >
                            {dl.taskName}
                          </div>
                        ))}
                        {dayDeadlines.length > 2 && <span className="calendar-event-tag__more">+{dayDeadlines.length - 2}</span>}
                      </div>
                    </div>
                  );
                })}
              </div>
            </section>

            {/* Правая панель */}
            <aside className="calendar-side-panel">
              <div className="calendar-info-card">
                <h3 className="calendar-info-card__title">Upcoming</h3>
                <div className="calendar-info-card__list">
                   {/* Здесь список дедлайнов (аналогично твоей логике, но с новыми классами) */}
                   <p className="calendar-info-card__empty">Check your schedule</p>
                </div>
              </div>
            </aside>
          </div>
        </main>
      </div>

      {showAddModal && <DeadlineModal courses={courses} onSave={onAddDeadline} onClose={() => setShowAddModal(false)} />}
    </div>
  );
}
